import { forwardRef, useState, useEffect, useMemo } from 'react';
import { AnimatePresence } from 'framer-motion';
import { BlueprintDiscovery, PrimaryPurpose, ConversionGoalValue, AdvancedObjectiveKey } from '@/types/blueprint';
import { StepLayout } from '../StepLayout';
import { LayerProgress } from '../ui/LayerProgress';
import { SiteTopicLayer } from '../layers/SiteTopicLayer';
import { PrimaryPurposeLayer } from '../layers/PrimaryPurposeLayer';
import { SecondaryPurposeLayer } from '../layers/SecondaryPurposeLayer';
import { ConversionGoalsLayer } from '../layers/ConversionGoalsLayer';
import { AdvancedObjectivesLayer } from '../layers/AdvancedObjectivesLayer';
import { FoundationLayer, LAYER_ORDER } from '../data/foundationsData';
import { AnimationDirection } from '../utils/layerAnimations';
import { useLenisScroll } from '@/hooks/useLenisScroll';
import {
  deriveLayerFromAnswers,
  getAvailableGoals,
  pruneInvalidAnswers,
  getRelevantAdvancedQuestions,
  migrateLegacyDiscovery,
  canProceedToNextStep,
  isLayerComplete,
} from '../utils/foundationsUtils';

interface BusinessFoundationsStepProps {
  discovery: BlueprintDiscovery;
  onUpdate: (updates: Partial<BlueprintDiscovery>) => void;
  onBack?: () => void;
  onNext: () => void;
}

export const BusinessFoundationsStep = forwardRef<HTMLDivElement, BusinessFoundationsStepProps>(
  function BusinessFoundationsStep({
    discovery,
    onUpdate,
    onBack,
    onNext,
  }, ref) {
    // 1. Migrate legacy data on mount
    const migratedDiscovery = useMemo(
      () => migrateLegacyDiscovery(discovery),
      // Only run migration when discovery reference changes
      [discovery.mainConversionGoal, discovery.primaryPurpose]
    );

    // 2. Derive initial layer from saved answers (refresh-safe)
    const [currentLayer, setCurrentLayer] = useState<FoundationLayer>(
      () => deriveLayerFromAnswers(migratedDiscovery)
    );

    // 3. Track navigation direction for animations
    const [direction, setDirection] = useState<AnimationDirection>('forward');

    // 4. Scroll to top on layer change
    const { scrollTo } = useLenisScroll();

    useEffect(() => {
      // Guard: anchor may not exist yet during AnimatePresence transitions
      requestAnimationFrame(() => {
        if (document.getElementById('step-header-anchor')) {
          scrollTo('#step-header-anchor', { duration: 0.5, offset: -120 });
        }
      });
    }, [currentLayer, scrollTo]);

    // Helper to navigate with direction tracking
    const navigateToLayer = (targetLayer: FoundationLayer) => {
      const currentIndex = LAYER_ORDER.indexOf(currentLayer);
      const targetIndex = LAYER_ORDER.indexOf(targetLayer);
      setDirection(targetIndex > currentIndex ? 'forward' : 'back');
      setCurrentLayer(targetLayer);
    };

    // 4. Apply migration if needed (one-time)
    useEffect(() => {
      const needsMigration =
        discovery.mainConversionGoal &&
        !discovery.primaryPurpose;

      if (needsMigration) {
        const migrated = migrateLegacyDiscovery(discovery);
        if (migrated !== discovery) {
          onUpdate(migrated);
        }
      }
    }, []); // Only on mount

    // 5. Track completed layers for progress indicator
    const completedLayers = LAYER_ORDER.filter(layer =>
      isLayerComplete(layer, discovery)
    );

    // 6. Handle site topic selection
    const handleSiteTopicSelect = (topic: string) => {
      onUpdate({ siteTopic: topic });
      // Auto-advance after short delay with forward direction
      setTimeout(() => navigateToLayer('purpose'), 400);
    };

    // 7. Handle primary purpose selection with pruning
    const handlePrimaryPurposeSelect = (purpose: PrimaryPurpose) => {
      const pruned = pruneInvalidAnswers(discovery, purpose, discovery.secondaryPurposes);
      onUpdate({
        primaryPurpose: purpose,
        ...pruned,
      });
      // Auto-advance after short delay with forward direction
      setTimeout(() => navigateToLayer('secondary'), 400);
    };

    // 7. Handle secondary purposes change with pruning
    const handleSecondaryPurposesChange = (purposes: PrimaryPurpose[]) => {
      // Filter out primary purpose if accidentally included
      const filtered = purposes.filter(p => p !== discovery.primaryPurpose);
      const pruned = pruneInvalidAnswers(discovery, discovery.primaryPurpose, filtered);
      onUpdate({
        secondaryPurposes: filtered,
        ...pruned,
      });
    };

    // 8. Handle secondary continue
    const handleSecondaryContinue = () => {
      // Mark secondary as answered even if empty
      if (discovery.secondaryPurposes === undefined) {
        onUpdate({ secondaryPurposes: [] });
      }
      navigateToLayer('conversion');
    };

    // 9. Handle secondary skip
    const handleSecondarySkip = () => {
      onUpdate({ secondaryPurposes: [] });
      navigateToLayer('conversion');
    };

    // 10. Handle conversion goals change
    const handleConversionGoalsChange = (goals: ConversionGoalValue[]) => {
      onUpdate({ conversionGoals: goals });
    };

    // 11. Handle conversion continue
    const handleConversionContinue = () => {
      // Check if there are relevant advanced questions for the selected goals
      const hasAdvanced = getRelevantAdvancedQuestions(discovery.conversionGoals).length > 0;
      if (hasAdvanced) {
        navigateToLayer('advanced');
      } else {
        // No advanced questions - mark as answered (empty) and proceed to next step
        onUpdate({ advancedObjectives: {} });
        onNext();
      }
    };

    // 12. Handle advanced objective change
    const handleAdvancedChange = (key: AdvancedObjectiveKey, value: string) => {
      onUpdate({
        advancedObjectives: {
          ...discovery.advancedObjectives,
          [key]: value,
        },
      });
    };

    // 13. Handle advanced continue/skip
    const handleAdvancedContinue = () => {
      // Mark as answered if not yet
      if (discovery.advancedObjectives === undefined) {
        onUpdate({ advancedObjectives: {} });
      }
      onNext();
    };

    // 14. Handle layer navigation via progress indicator
    const handleLayerClick = (layer: FoundationLayer) => {
      const targetIndex = LAYER_ORDER.indexOf(layer);
      const currentIndex = LAYER_ORDER.indexOf(currentLayer);
      // Allow going back to any previous layer, or forward to completed layers
      if (targetIndex !== currentIndex && (targetIndex < currentIndex || completedLayers.includes(layer))) {
        navigateToLayer(layer);
      }
    };

    // 15. Compute available goals
    const availableGoals = getAvailableGoals(
      discovery.primaryPurpose,
      discovery.secondaryPurposes
    );

    // 16. Check if fallback needed
    const showGoalsFallback =
      discovery.primaryPurpose &&
      discovery.secondaryPurposes !== undefined &&
      availableGoals.length === 0;

    // 17. Get advanced questions
    const advancedQuestions = getRelevantAdvancedQuestions(discovery.conversionGoals);

    // 18. Check if can proceed to next step
    const canGoNext = canProceedToNextStep(discovery);

    return (
      <StepLayout
        ref={ref}
        act="discovery"
        stepNumber={1}
        title="Business Foundations"
        framing="Let's understand your business and what success looks like."
        onBack={onBack}
        onNext={onNext}
        canGoNext={canGoNext}
        hideNavigation={true} // We handle navigation internally
      >
        <div className="space-y-6">
          {/* Layer Progress */}
          <LayerProgress
            currentLayer={currentLayer}
            onLayerClick={handleLayerClick}
            completedLayers={completedLayers}
          />

          {/* Layer Content - Fixed Stage Container */}
          <div className="relative min-h-[70vh] overflow-clip">
            <AnimatePresence mode="popLayout" initial={false}>
              {currentLayer === 'topic' && (
                <SiteTopicLayer
                  key="topic"
                  selected={discovery.siteTopic}
                  onSelect={handleSiteTopicSelect}
                  direction={direction}
                />
              )}

              {currentLayer === 'purpose' && (
                <PrimaryPurposeLayer
                  key="purpose"
                  selected={discovery.primaryPurpose}
                  onSelect={handlePrimaryPurposeSelect}
                  direction={direction}
                />
              )}

              {currentLayer === 'secondary' && (
                <SecondaryPurposeLayer
                  key="secondary"
                  primaryPurpose={discovery.primaryPurpose}
                  selected={discovery.secondaryPurposes || []}
                  onChange={handleSecondaryPurposesChange}
                  onBack={() => navigateToLayer('purpose')}
                  onContinue={handleSecondaryContinue}
                  onSkip={handleSecondarySkip}
                  direction={direction}
                />
              )}

              {currentLayer === 'conversion' && (
                <ConversionGoalsLayer
                  key="conversion"
                  availableGoals={availableGoals}
                  selected={discovery.conversionGoals || []}
                  onChange={handleConversionGoalsChange}
                  onBack={() => navigateToLayer('secondary')}
                  onContinue={handleConversionContinue}
                  showFallback={showGoalsFallback}
                  direction={direction}
                />
              )}

              {currentLayer === 'advanced' && (
                <AdvancedObjectivesLayer
                  key="advanced"
                  questions={advancedQuestions}
                  answers={discovery.advancedObjectives || {}}
                  onChange={handleAdvancedChange}
                  onBack={() => navigateToLayer('conversion')}
                  onContinue={handleAdvancedContinue}
                  onSkip={handleAdvancedContinue}
                  direction={direction}
                />
              )}
            </AnimatePresence>
          </div>
        </div>
      </StepLayout>
    );
  }
);

import { useEffect, useMemo, useState, forwardRef, useRef } from 'react';
import { motion } from 'framer-motion';
import { BlueprintDesign } from '@/types/blueprint';
import { StepLayout } from '../StepLayout';
import { Label } from '@/components/ui/label';
import { VoiceAxisSlider } from '../ui/VoiceAxisSlider';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { RotateCcw, Lock } from 'lucide-react';
import { cn } from '@/lib/utils';
import { ColorWheelDiagram, RelationshipIcon } from '../ui/ColorWheelDiagram';
import { InteractiveColorWheel } from '../ui/InteractiveColorWheel';
import { ConfiguratorCardSurface } from '../ui/ConfiguratorCardSurface';
import { ConfiguratorCardHeader } from '../ui/ConfiguratorCardHeader';
import { CopyHexButton } from '../ui/ColorWheelDiagram';
import { AnimatedLockIcon } from '../ui/AnimatedLockIcon';

// Energy zones and conversion functions
const ENERGY_ZONES = ['Calm', 'Gentle', 'Balanced', 'Vibrant', 'Energetic'] as const;

const energyToZone = (value: number): string => {
  if (value <= 2) return 'Calm';
  if (value <= 4) return 'Gentle';
  if (value <= 6) return 'Balanced';
  if (value <= 8) return 'Vibrant';
  return 'Energetic';
};

const zoneToEnergy = (zone: string): number => {
  const map: Record<string, number> = {
    'Calm': 2, 'Gentle': 4, 'Balanced': 5, 'Vibrant': 7, 'Energetic': 9
  };
  return map[zone] ?? 5;
};

// Contrast zones and conversion functions
const CONTRAST_ZONES = ['Subtle', 'Soft', 'Balanced', 'Strong', 'Bold'] as const;

const contrastToZone = (value: number): string => {
  if (value <= 2) return 'Subtle';
  if (value <= 4) return 'Soft';
  if (value <= 6) return 'Balanced';
  if (value <= 8) return 'Strong';
  return 'Bold';
};

const zoneToContrast = (zone: string): number => {
  const map: Record<string, number> = {
    'Subtle': 2, 'Soft': 4, 'Balanced': 5, 'Strong': 7, 'Bold': 9
  };
  return map[zone] ?? 5;
};

interface ColorPaletteStepProps {
  design: BlueprintDesign;
  onUpdate: (updates: Partial<BlueprintDesign>) => void;
  onBack: () => void;
  onNext: () => void;
}

const colourRelationships = [
  {
    value: 'monochrome',
    label: 'Monochrome',
    description: 'Single hue, tonal depth, calm and editorial',
    angle: 0,
  },
  {
    value: 'analogous',
    label: 'Analogous',
    description: 'Neighbouring hues, cohesive and premium',
    angle: 30,
  },
  {
    value: 'complementary',
    label: 'Complementary',
    description: 'High contrast, bold accent focus',
    angle: 180,
  },
  {
    value: 'triadic',
    label: 'Triadic',
    description: 'Balanced contrast, expressive energy',
    angle: 120,
  },
] as const;

// Base hues based on aesthetic
const aestheticBaseHues: Record<string, number> = {
  minimal: 0, // Neutral grays
  dark_cinematic: 240, // Deep blue
  urban: 30, // Orange/brown
  luxury: 45, // Gold
  playful: 300, // Magenta
  tech: 200, // Cyan
};

function hslToHex(h: number, s: number, l: number): string {
  l /= 100;
  const a = (s * Math.min(l, 1 - l)) / 100;
  const f = (n: number) => {
    const k = (n + h / 30) % 12;
    const color = l - a * Math.max(Math.min(k - 3, 9 - k, 1), -1);
    return Math.round(255 * color)
      .toString(16)
      .padStart(2, '0');
  };
  return `#${f(0)}${f(8)}${f(4)}`;
}

// Convert hex color to hue (0-360)
function hexToHue(hex: string): number | null {
  // Remove # if present and validate
  const cleanHex = hex.replace('#', '').trim();
  if (!/^[0-9A-Fa-f]{6}$/.test(cleanHex) && !/^[0-9A-Fa-f]{3}$/.test(cleanHex)) {
    return null;
  }

  // Expand 3-digit hex
  const fullHex = cleanHex.length === 3
    ? cleanHex.split('').map(c => c + c).join('')
    : cleanHex;

  const r = parseInt(fullHex.slice(0, 2), 16) / 255;
  const g = parseInt(fullHex.slice(2, 4), 16) / 255;
  const b = parseInt(fullHex.slice(4, 6), 16) / 255;

  const max = Math.max(r, g, b);
  const min = Math.min(r, g, b);
  const delta = max - min;

  if (delta === 0) return 0; // Gray, no hue

  let hue = 0;
  if (max === r) {
    hue = ((g - b) / delta) % 6;
  } else if (max === g) {
    hue = (b - r) / delta + 2;
  } else {
    hue = (r - g) / delta + 4;
  }

  hue = Math.round(hue * 60);
  if (hue < 0) hue += 360;

  return hue;
}

function hexToHslData(hex: string): { h: number, s: number, l: number } | null {
  const cleanHex = hex.replace('#', '').trim();
  if (!/^[0-9A-Fa-f]{6}$/.test(cleanHex) && !/^[0-9A-Fa-f]{3}$/.test(cleanHex)) return null;

  const fullHex = cleanHex.length === 3 ? cleanHex.split('').map(c => c + c).join('') : cleanHex;
  const r = parseInt(fullHex.slice(0, 2), 16) / 255;
  const g = parseInt(fullHex.slice(2, 4), 16) / 255;
  const b = parseInt(fullHex.slice(4, 6), 16) / 255;

  const max = Math.max(r, g, b);
  const min = Math.min(r, g, b);
  const delta = max - min;

  let h = 0, s = 0, l = (max + min) / 2;

  if (delta !== 0) {
    s = l > 0.5 ? delta / (2 - max - min) : delta / (max + min);
    if (max === r) h = ((g - b) / delta) + (g < b ? 6 : 0);
    else if (max === g) h = (b - r) / delta + 2;
    else h = (r - g) / delta + 4;
    h /= 6;
  }

  return { h: Math.round(h * 360), s: Math.round(s * 100), l: Math.round(l * 100) };
}

function generatePalette(
  relationship: string,
  customBaseHue: number,
  energy: number,
  contrast: number
): { role: string; color: string }[] {
  const baseHue = customBaseHue;
  const baseSaturation = 10 + (energy - 1) * 8; // 10-82% based on energy
  const lightnessSpread = 10 + (contrast - 1) * 5; // How much luminance varies

  const isMonochrome = relationship === 'monochrome';
  const saturation = isMonochrome ? Math.min(baseSaturation, 15) : baseSaturation;

  let hues: number[];
  switch (relationship) {
    case 'monochrome':
      hues = [baseHue, baseHue, baseHue, baseHue];
      break;
    case 'analogous':
      hues = [baseHue, baseHue + 30, baseHue - 30, baseHue + 15];
      break;
    case 'complementary':
      hues = [baseHue, baseHue, baseHue + 180, baseHue];
      break;
    case 'triadic':
      hues = [baseHue, baseHue + 120, baseHue + 240, baseHue + 60];
      break;
    default:
      hues = [baseHue, baseHue, baseHue, baseHue];
  }

  // Normalize hues
  hues = hues.map(h => ((h % 360) + 360) % 360);

  const baseLightness = 50;
  const primaryL = baseLightness;
  const secondaryL = baseLightness + lightnessSpread;
  const neutralL = 85 + (10 - contrast); // Lighter for low contrast
  const accentL = baseLightness - lightnessSpread / 2;

  return [
    { role: 'Primary', color: hslToHex(hues[0], saturation, primaryL) },
    { role: 'Secondary', color: hslToHex(hues[1], saturation * 0.7, secondaryL) },
    { role: 'Neutral', color: hslToHex(hues[2], isMonochrome ? 5 : saturation * 0.3, neutralL) },
    { role: 'Accent', color: hslToHex(hues[3], saturation * 1.2, accentL) },
  ];
}

export const ColorPaletteStep = forwardRef<HTMLDivElement, ColorPaletteStepProps>(
  function ColorPaletteStep({
    design,
    onUpdate,
    onBack,
    onNext,
  }, ref) {
    const relationship = design.colourRelationship || 'monochrome';
    const energy = design.paletteEnergy || 5;
    const contrast = design.paletteContrast || 5;

    // Get default hue based on aesthetic
    const defaultHue = aestheticBaseHues[design.visualStyle || 'minimal'] || 0;
    const baseHue = design.baseHue ?? defaultHue;

    const [paletteMode, setPaletteMode] = useState<'system' | 'manual'>('system');
    const [lockedColors, setLockedColors] = useState<Record<string, string>>({});

    // Generate palette whenever inputs change
    const systemPalette = useMemo(() => {
      return generatePalette(relationship, baseHue, energy, contrast);
    }, [relationship, baseHue, energy, contrast]);

    const activePalette = useMemo(() => {
      return systemPalette.map(sys => {
        if (lockedColors[sys.role]) {
          return { ...sys, color: lockedColors[sys.role] };
        }
        return sys;
      });
    }, [systemPalette, lockedColors]);

    // Update generated palette when it changes
    useEffect(() => {
      onUpdate({ generatedPalette: activePalette });
    }, [activePalette]);

    const handleManualHexChange = (role: string, hex: string) => {
      setLockedColors(prev => ({ ...prev, [role]: hex }));
    };

    const toggleLock = (role: string, currentColor: string) => {
      setLockedColors(prev => {
        const next = { ...prev };
        if (next[role]) {
          delete next[role];
        } else {
          next[role] = currentColor;
        }
        return next;
      });
    };

    // Initialize with defaults if not set
    useEffect(() => {
      if (!design.colourRelationship) {
        onUpdate({
          colourRelationship: 'monochrome',
          paletteEnergy: 5,
          paletteContrast: 5,
          baseHue: defaultHue,
        });
      }
    }, []);

    const advisoryMetrics = useMemo(() => {
      if (paletteMode !== 'manual') return null;

      const hslArr = activePalette.map(p => hexToHslData(p.color)).filter(Boolean) as { h: number, s: number, l: number }[];
      if (hslArr.length < 4) return { relationship: 'CUSTOM', energy: 'N/A', contrast: 'N/A' };

      const hues = hslArr.map(hsl => hsl.h);
      const hueDiffs = [
        Math.abs(hues[0] - hues[1]),
        Math.abs(hues[0] - hues[2]),
        Math.abs(hues[0] - hues[3])
      ].map(diff => diff > 180 ? 360 - diff : diff);

      let rel = 'CUSTOM';
      const avgDiff = hueDiffs.reduce((a, b) => a + b, 0) / 3;
      if (avgDiff < 15) rel = 'MONOCHROME';
      else if (hueDiffs.every(d => d > 15 && d < 60)) rel = 'ANALOGOUS';
      else if (hueDiffs.some(d => d > 150)) rel = 'COMPLEMENTARY';
      else if (hueDiffs.some(d => d > 90 && d < 150) || hueDiffs.every(d => d > 30)) rel = 'TRIADIC';

      const avgS = hslArr.reduce((sum, val) => sum + val.s, 0) / 4;
      let energyStr = 'BALANCED';
      if (avgS < 20) energyStr = 'CALM';
      else if (avgS < 40) energyStr = 'GENTLE';
      else if (avgS > 80) energyStr = 'ENERGETIC';
      else if (avgS > 60) energyStr = 'VIBRANT';

      const light = hslArr.map(hsl => hsl.l);
      const Ldiff = Math.max(...light) - Math.min(...light);
      let contrastStr = 'BALANCED';
      if (Ldiff < 20) contrastStr = 'SUBTLE';
      else if (Ldiff < 40) contrastStr = 'SOFT';
      else if (Ldiff > 70) contrastStr = 'BOLD';
      else if (Ldiff > 50) contrastStr = 'STRONG';

      return { relationship: rel, energy: energyStr, contrast: contrastStr };
    }, [activePalette, paletteMode]);

    const handleRelationshipSelect = (value: typeof relationship) => {
      onUpdate({ colourRelationship: value });
    };

    const handleBaseHueChange = (hue: number) => {
      onUpdate({ baseHue: hue });
    };

    const handleResetHue = () => {
      onUpdate({ baseHue: defaultHue });
    };

    const hueDragRef = useRef<{ startX: number; startHue: number } | null>(null);

    const handleHueDragStart = (e: React.PointerEvent<HTMLDivElement>) => {
      if (e.button !== 0) return; // Only left click / main touch
      e.currentTarget.setPointerCapture(e.pointerId);
      hueDragRef.current = {
        startX: e.clientX,
        startHue: baseHue
      };
    };

    const handleHueDragMove = (e: React.PointerEvent<HTMLDivElement>) => {
      if (!hueDragRef.current) return;

      const deltaX = e.clientX - hueDragRef.current.startX;
      // 1 degree per 2 pixels dragged for fine control
      const deltaHue = Math.round(deltaX / 2);

      let newHue = (hueDragRef.current.startHue + deltaHue) % 360;
      if (newHue < 0) newHue += 360;

      handleBaseHueChange(newHue);
    };

    const handleHueDragEnd = (e: React.PointerEvent<HTMLDivElement>) => {
      e.currentTarget.releasePointerCapture(e.pointerId);
      hueDragRef.current = null;
    };

    const isHueCustomized = design.baseHue !== undefined && design.baseHue !== defaultHue;

    return (
      <StepLayout
        ref={ref}
        act="design"
        stepNumber={6}
        title="Color Palette"
        framing="Define your colour logic and palette."
        onBack={onBack}
        onNext={onNext}
      >
        <div className="space-y-12">
          {/* Colour Relationship Selector - Arc/Wheel Style */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
            className="space-y-6"
          >
            {/* Arc Selector */}
            <ConfiguratorCardSurface className="relative max-w-lg mx-auto overflow-hidden">
              <ConfiguratorCardHeader title="Color Logic" metaLabel="SYS.RELATION" delay={0.1} />
              <div className="w-full h-full flex flex-col items-center pt-16 pb-6 px-6">
                <div className="relative w-[384px] h-[180px] overflow-visible">
                  {/* Arc Background */}
                  <svg
                    viewBox="0 0 384 180"
                    className="absolute inset-0 w-full h-full"
                  >
                    {/* Arc path */}
                    <path
                      d="M 52 170 A 140 140 0 0 1 332 170"
                      fill="none"
                      stroke="hsl(var(--border))"
                      strokeWidth="40"
                      strokeLinecap="round"
                      className="opacity-30"
                    />
                  </svg>

                  {/* Relationship Options */}
                  {colourRelationships.map((rel, index) => {
                    const isSelected = relationship === rel.value;
                    // Symmetric arc positioning: apex (-90°) between icons 2 and 3
                    const startAngle = -160;
                    const endAngle = -20;
                    const totalSpan = endAngle - startAngle;
                    const spacing = totalSpan / (colourRelationships.length - 1);
                    const arcAngle = startAngle + (index * spacing);

                    const radius = 140;
                    const centerX = 192;
                    const centerY = 170;
                    const x = centerX + radius * Math.cos((arcAngle * Math.PI) / 180);
                    const y = centerY + radius * Math.sin((arcAngle * Math.PI) / 180);

                    // Convert to percentages based on the 384x180 viewBox
                    const xPercent = (x / 384) * 100;
                    const yPercent = (y / 180) * 100;

                    return (
                      <motion.button
                        key={rel.value}
                        type="button"
                        onClick={() => handleRelationshipSelect(rel.value as typeof relationship)}
                        className="absolute z-10"
                        style={{
                          left: `${xPercent}%`,
                          top: `${yPercent}%`,
                          transform: 'translate(-50%, -50%)',
                        }}
                      >
                        <div className={cn(
                          'w-16 h-16 rounded-full flex items-center justify-center transition-all duration-300',
                          'border-2',
                          isSelected
                            ? 'border-accent bg-accent/20 shadow-[0_0_24px_hsl(var(--accent)/0.4)]'
                            : 'border-border/50 bg-muted/40 hover:border-border hover:bg-muted/60'
                        )}>
                          {/* Mini color wheel indicator */}
                          <RelationshipIcon type={rel.value} isSelected={isSelected} />
                        </div>
                      </motion.button>
                    );
                  })}
                </div>

                {/* Center Label - positioned below the arc */}
                <div className="text-center w-[384px]">
                  <motion.p
                    key={relationship}
                    initial={{ opacity: 0, y: 5 }}
