                </div>

                {/* Uploaded Files */}
                {files.length > 0 && (
                  <div className="space-y-3">
                    <Label className="text-sm font-medium text-foreground">Uploaded Files</Label>
                    <div className="grid gap-3">
                      {files.map(file => (
