                            </Select>
                            <Select value={file.style} onValueChange={(v) => handleUpdateFile(file.id, { style: v })}>
                              <SelectTrigger className="w-[75px] sm:w-[90px] h-8 text-xs shrink-0"><SelectValue placeholder="Style" /></SelectTrigger>
