                          <div className="pt-2">
                            <button type="button" className="px-5 py-2.5 bg-foreground text-background rounded-lg hover:bg-foreground/90 transition-colors" style={{ fontFamily: `'BlueprintCustom-${f.id}'`, fontWeight: f.weight, fontStyle: f.style }}>
                              Start Building
