import React, { useEffect, useRef } from 'react';
import lottie, { AnimationItem } from 'lottie-web';

import unlockData from '@/assets/ui/unlock.json';
import unlockAmberData from '@/assets/ui/unlock_amber.json';
import { cn } from '@/lib/utils';

interface AnimatedLockIconProps {
    isLocked: boolean;
    className?: string;
}

export const AnimatedLockIcon: React.FC<AnimatedLockIconProps> = ({ isLocked, className }) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const animRef = useRef<AnimationItem | null>(null);
    const isReversingRef = useRef(false);
    const prevLockedRef = useRef(isLocked);

    // Use a stable reference to keep track of initializing
    const initLottie = (data: any, goToFrame: number | 'end') => {
        if (animRef.current) {
            animRef.current.destroy();
        }
        const anim = lottie.loadAnimation({
            container: containerRef.current!,
            renderer: 'svg',
            loop: false,
            autoplay: false,
            animationData: data,
        });
        animRef.current = anim;

        anim.addEventListener('DOMLoaded', () => {
            if (goToFrame === 'end') {
                anim.goToAndStop(Math.max(0, anim.totalFrames - 1), true);
            } else {
                anim.goToAndStop(goToFrame, true);
            }
        });

        anim.addEventListener('complete', () => {
            if (isReversingRef.current) {
                // We finished returning to rest state.
                isReversingRef.current = false;
                // Instantly swap to Neutral
                initLottie(unlockData, 0);
            }
        });

        return anim;
    };

    useEffect(() => {
        if (!containerRef.current) return;
        initLottie(isLocked ? unlockAmberData : unlockData, isLocked ? 'end' : 0);

        return () => {
            if (animRef.current) {
                animRef.current.destroy();
                animRef.current = null;
            }
        };
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    useEffect(() => {
        if (prevLockedRef.current === isLocked) return;
        prevLockedRef.current = isLocked;

        const anim = animRef.current;
        if (!anim) return;

        if (isLocked) {
            // False -> True (Locking/Engaging Amber)
            isReversingRef.current = false;
            // Instantly swap to amber, keeping on last frame
            initLottie(unlockAmberData, 'end');
        } else {
            // True -> False (Unlocking/Reverting to Neutral)
            // Play backwards to return to resting state
            isReversingRef.current = true;
            anim.setDirection(-1);
            anim.play();
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isLocked]);

    const handleMouseEnter = () => {
        // If engaged, do nothing (keep on last frame)
        if (isLocked) return;
        // If currently reversing back to neutral, do not interrupt
        if (isReversingRef.current) return;

        // If neutral, play forward
        if (animRef.current) {
            animRef.current.setDirection(1);
            animRef.current.play();
        }
    };

    const handleMouseLeave = () => {
        // If engaged, do nothing
        if (isLocked) return;
        // If currently reversing back to neutral, do not interrupt
        if (isReversingRef.current) return;

        // If neutral, instantly reset to frame 0
        if (animRef.current) {
            animRef.current.goToAndStop(0, true);
        }
    };

    return (
        <div
            ref={containerRef}
            className={cn("w-4 h-4", className)}
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
        />
    );
};

import { createContext, useContext, useEffect, useRef, ReactNode, useState } from 'react';
import Lenis from 'lenis';
import { motion, useScroll, MotionValue, useMotionValue } from 'framer-motion';

interface SmoothScrollContextType {
  lenis: Lenis | null;
  isReady: boolean;
  enabled: boolean;
  scrollY: MotionValue<number>;
  scrollYProgress: MotionValue<number>;
  isNavigating: MotionValue<boolean>;
  scrollVelocity: MotionValue<number>;
  scrollTo: (target: any, options?: any) => void;
}

const SmoothScrollContext = createContext<SmoothScrollContextType | null>(null);

export const useSmoothScroll = (): SmoothScrollContextType => {
  const context = useContext(SmoothScrollContext);

  // Hooks must be called unconditionally
  const fallbackScrollY = useMotionValue(0);
  const fallbackScrollYProgress = useMotionValue(0);
  const fallbackIsNavigating = useMotionValue(false);
  const fallbackScrollVelocity = useMotionValue(0);

  if (!context) {
    return {
      lenis: null,
      isReady: false,
      enabled: false,
      scrollY: fallbackScrollY,
      scrollYProgress: fallbackScrollYProgress,
      isNavigating: fallbackIsNavigating,
      scrollVelocity: fallbackScrollVelocity,
      scrollTo: () => { }
    };
  }

  return context;
};

interface SmoothScrollProviderProps {
  children: ReactNode;
  enabled?: boolean;
}

export function SmoothScrollProvider({ children, enabled = true }: SmoothScrollProviderProps) {
  const [lenis, setLenis] = useState<Lenis | null>(null);
  const [isReady, setIsReady] = useState(false);

  // Refs for internal state tracking
  const rafIdRef = useRef<number | null>(null);
  const isSignaledRef = useRef(false);

  // Global Motion Governance: track velocity intent for Class B motion freezing
  const isNavigating = useMotionValue(false);
  const scrollVelocity = useMotionValue(0);

  // Global Scroll Authority - Sampled once at the root
  const { scrollY, scrollYProgress } = useScroll();

  const scrollTo = (target: any, options?: any) => {
    lenis?.scrollTo(target, options);
  };

  useEffect(() => {
    if (!enabled) {
      setIsReady(false);
      isSignaledRef.current = false;
      return;
    }

    // Check for reduced motion preference
    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (prefersReducedMotion) {
      setIsReady(true);
      isSignaledRef.current = true;
      return;
    }

    let lenisInstance: Lenis | null = null;

    try {
      // Initialize Lenis with heavy inertial settings for cinematic momentum
      lenisInstance = new Lenis({
        lerp: 0.1,
        duration: 1.5,
        smoothWheel: true,
        wheelMultiplier: 0.9,
        touchMultiplier: 1.5,
        infinite: false,
        orientation: 'vertical',
        gestureOrientation: 'vertical',
      });

      setLenis(lenisInstance);

      // Single-Tick Ownership: Driving Lenis strictly via RAF
      function raf(time: number) {
        if (!lenisInstance) return;
        lenisInstance.raf(time);

        // Update navigation state based on velocity threshold (0.5px/ms)
        const velocity = Math.abs(lenisInstance.velocity);
        scrollVelocity.set(lenisInstance.velocity);

        if (isNavigating.get() !== (velocity > 0.5)) {
          isNavigating.set(velocity > 0.5);
        }

        rafIdRef.current = requestAnimationFrame(raf);

        if (!isSignaledRef.current) {
          isSignaledRef.current = true;
          setIsReady(true);
        }
      }

      rafIdRef.current = requestAnimationFrame(raf);
    } catch (error) {
      setIsReady(true);
      isSignaledRef.current = true;
    }

    return () => {
      if (rafIdRef.current) {
        cancelAnimationFrame(rafIdRef.current);
      }
      if (lenisInstance) {
        lenisInstance.destroy();
      }
      setLenis(null);
      setIsReady(false);
      isSignaledRef.current = false;
    };
  }, [enabled]);

  return (
    <SmoothScrollContext.Provider value={{ lenis, isReady, enabled, scrollY, scrollYProgress, isNavigating, scrollVelocity, scrollTo }}>
      {children}
    </SmoothScrollContext.Provider>
  );
}

import React, { useEffect, useRef } from "react";
import Lottie, { LottieRefCurrentProps } from "lottie-react";

interface AnimatedButtonIconProps {
    animationData: any;
    isActive: boolean;
    className?: string;
    staticFrame?: number;
    playOnVisible?: boolean;
    playVisibleDelay?: number;
}

export const AnimatedButtonIcon = React.memo(({
    animationData,
    isActive,
    className = "",
    staticFrame = 0,
    playOnVisible = false,
    playVisibleDelay = 0
}: AnimatedButtonIconProps) => {
    const lottieRef = useRef<LottieRefCurrentProps>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const hasPlayedVisible = useRef(false);
    const wasActive = useRef(false);

    // Initial load handling: Snap to the static frame ONLY if we are NOT using playOnVisible
    useEffect(() => {
        if (lottieRef.current && !isActive && !playOnVisible) {
            lottieRef.current.goToAndStop(staticFrame, true);
        }
    }, [lottieRef.current, staticFrame, playOnVisible]);

    // Handle intersection for playOnVisible (runs once when scrolled into view)
    useEffect(() => {
        if (!playOnVisible || !containerRef.current) return;

        let timeoutId: NodeJS.Timeout;

        const observer = new IntersectionObserver((entries) => {
            if (entries[0].isIntersecting && !hasPlayedVisible.current && !isActive) {
                hasPlayedVisible.current = true;

                if (playVisibleDelay > 0) {
                    timeoutId = setTimeout(() => {
                        // Double check isActive hasn't changed while waiting
                        if (!wasActive.current) {
                            lottieRef.current?.goToAndPlay(0, true);
                        }
                    }, playVisibleDelay);
                } else {
                    lottieRef.current?.goToAndPlay(0, true);
                }
            }
        }, { threshold: 0.1 });

        observer.observe(containerRef.current);

        return () => {
            observer.disconnect();
            if (timeoutId) clearTimeout(timeoutId);
        };
    }, [playOnVisible, playVisibleDelay, isActive]);

    // Hover state handling
    useEffect(() => {
        if (!lottieRef.current) return;

        if (isActive) {
            wasActive.current = true;
            lottieRef.current.goToAndPlay(0, true);
        } else if (wasActive.current) {
            wasActive.current = false;
            lottieRef.current.goToAndStop(staticFrame, true);
        }
    }, [isActive, staticFrame]);

    return (
        <div ref={containerRef} className={`flex items-center justify-center flex-shrink-0 ${className}`}>
            <Lottie
                lottieRef={lottieRef}
                animationData={animationData}
                loop={false}
                autoplay={false}
                style={{ width: "100%", height: "100%" }}
            />
        </div>
    );
});

AnimatedButtonIcon.displayName = "AnimatedButtonIcon";

import React, { useEffect, useRef } from "react";
import Lottie, { LottieRefCurrentProps } from "lottie-react";

interface BenefitIconLottieProps {
    animationData: any;
    isActive: boolean;
    color: string;
    className?: string;
    staticFrame?: number;
    hasPlayedOnce?: boolean;
}

export const BenefitIconLottie = React.memo(({
    animationData,
    isActive,
    color,
    className = "",
    staticFrame = 0,
    hasPlayedOnce = false
}: BenefitIconLottieProps) => {
    const lottieRef = useRef<LottieRefCurrentProps>(null);

    // Initial mount: snap to the static frame
    useEffect(() => {
        if (lottieRef.current) {
            lottieRef.current.goToAndStop(staticFrame, true);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    // Hover / entrance trigger: play from frame 0, or snap back to static frame
    useEffect(() => {
        if (!lottieRef.current) return;

        if (isActive || hasPlayedOnce) {
            lottieRef.current.goToAndPlay(0, true);
        } else {
            lottieRef.current.goToAndStop(staticFrame, true);
        }
    }, [isActive, hasPlayedOnce, staticFrame]);

    return (
        <div
            // Container precisely matches original 48x48 bounds and styling
            className={`relative w-12 h-12 rounded bg-background border border-white/10 flex items-center justify-center flex-shrink-0 transition-all duration-500 ${className}`}
